    recipe:{nodeIds:["TEX_01","TEX_02","TEX_03","TEX_05"],connections:[["TEX_01","TEX_02"],["TEX_02","TEX_03"],["TEX_03","TEX_05"]],names:{TEX_01:["Concrete Aggregate","MACRO + MICRO"],TEX_02:["Rain Weathering","VERTICAL MASK"],TEX_03:["Panel Seams","STRUCTURE"],TEX_05:["Concrete Surface","MATERIAL BOARD"]}},
    steps:[{title:"Compose by scale",body:"Real concrete has at least three readable scales: large casting variation, medium stains, and fine aggregate. Establish those scales before adding color.",mode:"textures",node:"TEX_01",target:"#inspectorContent"},{title:"Weather with a directional mask",body:"Use low-frequency distortion for vertical rain streaks and darker collection zones. Weathering should follow gravity, not swirl equally in every direction.",mode:"textures",node:"TEX_02",target:"#inspectorContent"},{title:"Add construction logic",body:"Panel seams are structural information. Keep their rhythm straighter and sharper than the organic noise beneath them.",mode:"textures",node:"TEX_03",target:"#inspectorContent"},{title:"Keep the palette narrow",body:"Concrete realism comes from value and roughness variation. Avoid saturated color; let lighting reveal the aggregate and recessed seams.",mode:"textures",node:"TEX_05",target:"#glCanvas"},{title:"Verify on a camera",body:"Switch to Scene to inspect the same lesson with its dedicated camera. Return here to judge the full material board without a vignette.",mode:"scene",node:"CAM_06",target:"#glCanvas"}]
