    recipe:{nodeIds:["TEX_01","TEX_03","TEX_04","TEX_05"],connections:[["TEX_01","TEX_03"],["TEX_03","TEX_04"],["TEX_04","TEX_05"]],names:{TEX_01:["Occupancy Seed","DETERMINISTIC"],TEX_03:["Window Grid","BAYS + FLOORS"],TEX_04:["Glass / Concrete Grade","MATERIAL SPLIT"],TEX_05:["Facade Composite","MATERIAL BOARD"]}},
    steps:[{title:"Start with architectural rhythm",body:"Choose a repeat that reads as floors and bays. Window proportions and spacing must feel plausible before surface noise is introduced.",mode:"textures",node:"TEX_03",target:"#inspectorContent"},{title:"Separate material families",body:"Concrete, metal frames, and glass need distinct value ranges. Dark recessed glass makes the frame thickness legible without painted outlines.",mode:"textures",node:"TEX_04",target:"#inspectorContent"},{title:"Seed occupancy, not brightness",body:"Use noise only to decide which windows are occupied. Keep the window geometry fixed so the building does not boil or deform over time.",mode:"textures",node:"TEX_01",target:"#inspectorContent"},{title:"Use sparse emission",body:"Raise Material Mix to light more rooms. Sparse warm and cool windows feel inhabited; a uniformly glowing grid looks synthetic.",mode:"textures",node:"TEX_05",target:"#glCanvas"},{title:"Check at scene distance",body:"Switch to Scene and verify that window bays survive perspective while fine aggregate disappears naturally with distance.",mode:"scene",node:"CAM_06",target:"#glCanvas"}]
