    recipe:{nodeIds:["TEX_01","TEX_02","TEX_04","TEX_05"],connections:[["TEX_01","TEX_02"],["TEX_02","TEX_04"],["TEX_04","TEX_05"]],names:{TEX_01:["Stone Aggregate","FINE GRAINS"],TEX_02:["Repairs + Cracks","IRREGULAR MASKS"],TEX_04:["Road Value Grade","NARROW RANGE"],TEX_05:["Asphalt Composite","MATERIAL BOARD"]}},
    steps:[{title:"Anchor a dark base",body:"Asphalt is a narrow, low-value material. Begin dark enough that aggregate appears through lighting rather than as white painted speckles.",mode:"textures",node:"TEX_04",target:"#inspectorContent"},{title:"Add fine aggregate",body:"Raise Grain Scale until individual stones become texture rather than blobs. Roughness controls how frequently brighter aggregate catches the eye.",mode:"textures",node:"TEX_01",target:"#inspectorContent"},{title:"Make repairs larger than grains",body:"Repair patches and stains belong to a much larger scale than aggregate. Domain Warp breaks their edges without turning the road into liquid marble.",mode:"textures",node:"TEX_02",target:"#inspectorContent"},{title:"Reserve clean shapes for markings",body:"Lane paint is manufactured, so it should stay straighter and cleaner than the road. Contrast between procedural wear and graphic markings sells the composition.",mode:"textures",node:"TEX_05",target:"#glCanvas"},{title:"Keep the surface static",body:"Texture Speed is zero. Animate reflected light or rain in a later layer, not the stones, cracks, or repair patches themselves.",mode:"textures",node:"TEX_01",target:"#inspectorContent"}]
