    recipe:{nodeIds:["TEX_01","TEX_02","TEX_03","TEX_04","TEX_05"],connections:[["TEX_01","TEX_02"],["TEX_02","TEX_03"],["TEX_03","TEX_04"],["TEX_04","TEX_05"]],names:{TEX_01:["Surface Frequencies","MACRO / MICRO"],TEX_02:["Weathering","DIRECTIONAL"],TEX_03:["Structure Masks","PANELS / WINDOWS"],TEX_04:["Material Palette","CONCRETE / GLASS"],TEX_05:["City Material Stack","FINAL COMPOSITE"]}},
    steps:[{title:"1. Establish structure",body:"Think in masks first: wall, seam, frame, glass, road, and marking. These categories describe what the surface is before they describe its color.",mode:"textures",node:"TEX_03",target:"#graphCanvas"},{title:"2. Layer frequencies",body:"Use broad noise for casting and repairs, medium noise for grime, and fine noise for aggregate. Avoid asking one octave to represent every physical scale.",mode:"textures",node:"TEX_01",target:"#inspectorContent"},{title:"3. Apply directional history",body:"Weathering follows gravity, runoff, traffic, and contact edges. Warp those masks gently while keeping architectural structure intact.",mode:"textures",node:"TEX_02",target:"#inspectorContent"},{title:"4. Grade by material",body:"Assign separate ranges to concrete, glass, metal, asphalt, and emission. Realism improves when each family keeps a consistent value and roughness identity.",mode:"textures",node:"TEX_04",target:"#inspectorContent"},{title:"5. Add story sparingly",body:"Occupancy and warm/cool windows suggest life. They are the accent layer, not the base texture, so keep most windows dark.",mode:"textures",node:"TEX_05",target:"#glCanvas"},{title:"6. Validate both views",body:"Inspect the full rectangular board for tiling and balance, then switch to Scene to test scale, perspective, and camera distance.",mode:"scene",node:"CAM_06",target:"#glCanvas"}]
